import '../models/cache_entry.dart';

/// Валидатор кэша. Позволяет "заморозить" записи — не идти в handler.
///
/// Сценарии использования:
/// - Offline-режим: приложение работает без сети
/// - Тесты: фиксированные данные без обращения к источнику
/// - Редактор: не перезаписывать несохранённые изменения
///
/// Если валидатор вернул true для просроченной записи —
/// кэш обновляет TTL и возвращает запись без вызова handler.
abstract interface class IAQCacheValidator {
  /// true = считать запись живой, не идти в handler.
  Future<bool> isValid(CacheEntry entry);

  /// Вызывается когда валидатор продлил жизнь записи.
  /// Можно использовать для логирования или метрик.
  Future<void> onExtended(CacheEntry entry);
}
